-- Ankara Kurban (kahramankazan) 2026 kurbanlık listesi — 150 satır
-- tenant_id: 00000000-0000-0000-0000-000000000002
-- TÜKENDİ = empty_share 0, aksi halde 7

ON CONFLICT (tenant_id, sacrifice_year, sacrifice_no) DO UPDATE SET
  share_weight = EXCLUDED.share_weight,
  share_price = EXCLUDED.share_price,
  empty_share = EXCLUDED.empty_share,
  animal_type = EXCLUDED.animal_type,
  sacrifice_time = EXCLUDED.sacrifice_time,
  last_edited_by = EXCLUDED.last_edited_by;
